command:
// Homebrew alternative Willpower rule: a major story achievement refreshes
// all Willpower. Restores every selected token's Willpower pool to full.
if (!game.settings.get("vampire-the-requiem-2e", "homebrewWillpower")) {
  ui.notifications.warn("Homebrew alternative Willpower gain is turned off (see system settings).");
  return;
}
const tokens = canvas.tokens?.controlled ?? [];
if (!tokens.length) {
  ui.notifications.warn("Select at least one token first.");
  return;
}
const refreshed = [];
for (const token of tokens) {
  const actor = token.actor;
  if (!actor || !actor.system?.willpower) continue;
  const max = Number(actor.system.willpower.max ?? 0);
  await actor.update({ "system.willpower.value": max });
  refreshed.push(actor.name);
}
if (refreshed.length) {
  const list = refreshed.map(a => `<li>${a}</li>`).join("");
  await ChatMessage.create({
    user: game.user.id,
    speaker: { alias: "Storyteller" },
    content: `<p><strong>Story achievement</strong> &mdash; Willpower fully restored for:</p><ul>${list}</ul>`
  });
}
